parameters.jsCode:
const response = $input.first().json;
const text = response.content[0].text;

let fit_score = 5;
let reason = "Could not parse";

try {
  const parsed = JSON.parse(text);
  fit_score = parsed.fit_score;
  reason = parsed.reason;
} catch(e) {
  const match = text.match(/"fit_score":\s*(\d+)/);
  if (match) fit_score = parseInt(match[1]);
}

return [{ json: { 
  fit_score, 
  reason,
  title: $('Loop Over Items').item.json.title,
  company: $('Loop Over Items').item.json.company,
  region: $('Loop Over Items').item.json.region,
  link: $('Loop Over Items').item.json.link,
  pubDate: $('Loop Over Items').item.json.pubDate
}}];

